import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react';
import { createPortal } from 'react-dom';
import ArvoButton from '../Button/Button';
import ArvoIconButton from '../IconButton/IconButton';
import ArvoCheckbox from '../Checkbox/Checkbox';
import ArvoTextbox from '../Textbox/Textbox';
import { useControllableState } from '../../hooks/useControllableState';
import { useOverlay } from '../../hooks/useOverlay';
import { useFocusTrap } from '../../hooks/useFocusTrap';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ArvoAlertDialogAction {
  label: string;
  icon?: string;
  onClick?: (e: React.MouseEvent) => void | false;
  isDisabled?: boolean;
  isLoading?: boolean;
  closeOnClick?: boolean;
}

export interface ArvoAlertDialogConfirmInput {
  label?: string;
  placeholder?: string;
  maxLength?: number;
  expectedValue?: string;
  onChange?: (value: string) => void;
}

export interface ArvoAlertDialogDontShow {
  label?: string;
  defaultChecked?: boolean;
  onChange?: (checked: boolean) => void;
}

export type ArvoAlertDialogVariant = 'warning' | 'info' | 'success' | 'error' | 'block';
export type ArvoAlertDialogSize = 'sm' | 'md' | 'lg';
export type ArvoAlertDialogCloseReason =
  | 'primary'
  | 'secondary'
  | 'close-button'
  | 'escape'
  | 'backdrop'
  | 'programmatic';

export interface ArvoAlertDialogProps {
  variant?: ArvoAlertDialogVariant;
  size?: ArvoAlertDialogSize;
  title: string;
  message?: string;
  content?: React.ReactNode;
  isOpen?: boolean;
  defaultOpen?: boolean;
  hasDangerAction?: boolean;
  primaryAction?: ArvoAlertDialogAction;
  secondaryAction?: ArvoAlertDialogAction | null;
  hasSecondaryBtn?: boolean;
  isClosable?: boolean;
  hasBackdrop?: boolean;
  closeOnBackdrop?: boolean;
  closeOnEscape?: boolean;
  confirmInput?: ArvoAlertDialogConfirmInput | null;
  dontShowAgain?: ArvoAlertDialogDontShow | boolean | null;
  isLoading?: boolean;
  isDisabled?: boolean;
  container?: HTMLElement | string | null;
  className?: string;
  onOpenChange?: (open: boolean) => void;
  onOpen?: () => void | false;
  onClose?: (detail: { reason: ArvoAlertDialogCloseReason }) => void | false;
  onConfirmInputChange?: (value: string) => void;
  onDontShowAgainChange?: (checked: boolean) => void;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const DEFAULT_PRIMARY: ArvoAlertDialogAction = { label: 'OK' };
const DEFAULT_SECONDARY: ArvoAlertDialogAction = { label: 'Cancel' };

function normalizeDontShow(
  value: ArvoAlertDialogDontShow | boolean | null | undefined,
): ArvoAlertDialogDontShow | null {
  if (value === null || value === undefined || value === false) return null;
  if (value === true) return {};
  return value;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const ArvoAlertDialog = forwardRef<HTMLDivElement, ArvoAlertDialogProps>(
  function ArvoAlertDialog(
    {
      variant = 'warning',
      size = 'md',
      title,
      message,
      content,
      isOpen: openProp,
      defaultOpen = false,
      hasDangerAction = false,
      primaryAction = DEFAULT_PRIMARY,
      secondaryAction,
      hasSecondaryBtn = true,
      isClosable = false,
      hasBackdrop = true,
      closeOnBackdrop = false,
      closeOnEscape = true,
      confirmInput = null,
      dontShowAgain = null,
      isLoading = false,
      isDisabled = false,
      container = null,
      className,
      onOpenChange,
      onOpen,
      onClose,
      onConfirmInputChange,
      onDontShowAgainChange,
    },
    ref,
  ) {
    const uid = useId();
    const panelId = `arvo-alert-dlg-${uid}`;
    const titleId = `arvo-alert-dlg-title-${uid}`;
    const bodyId = `arvo-alert-dlg-body-${uid}`;

    const rootRef = useRef<HTMLDivElement>(null);
    const panelRef = useRef<HTMLDivElement>(null);
    const inputElRef = useRef<HTMLInputElement | null>(null);

    useImperativeHandle(ref, () => rootRef.current!, []);

    // ── Controlled / Uncontrolled open state ────────────────────────────
    const [isOpen, setOpen] = useControllableState<boolean>(openProp, defaultOpen);

    // ── Confirm-input local state ───────────────────────────────────────
    const [confirmValue, setConfirmValue] = useState('');
    const isPrimaryDisabledByConfirm = confirmInput?.expectedValue
      ? confirmValue !== confirmInput.expectedValue
      : false;

    // Reset confirm input when dialog closes
    useEffect(() => {
      if (!isOpen) setConfirmValue('');
    }, [isOpen]);

    // ── Don't-show-again local state ────────────────────────────────────
    const dontShowConfig = normalizeDontShow(dontShowAgain);
    const [dontShowChecked, setDontShowChecked] = useState<boolean>(
      dontShowConfig?.defaultChecked ?? false,
    );

    // ── Overlay hub ─────────────────────────────────────────────────────
    const overlay = useOverlay();

    // ── Close handler ───────────────────────────────────────────────────
    const handleClose = useCallback(
      (reason: ArvoAlertDialogCloseReason) => {
        if (!isOpen) return;
        if (onClose?.({ reason }) === false) return;
        setOpen(false);
      },
      [isOpen, onClose, setOpen],
    );

    // ── onOpen lifecycle: fire once when the dialog transitions to open ──
    // (Allows consumers to veto open via returning false on initial mount.)
    const wasOpenRef = useRef(isOpen);
    useEffect(() => {
      if (!wasOpenRef.current && isOpen) {
        if (onOpen?.() === false) {
          setOpen(false);
          return;
        }
      }
      wasOpenRef.current = isOpen;
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Sync onOpenChange (skip first render to avoid spurious init call) ─
    const isFirstRenderRef = useRef(true);
    useEffect(() => {
      if (isFirstRenderRef.current) {
        isFirstRenderRef.current = false;
        return;
      }
      onOpenChange?.(isOpen);
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Register with overlay hub at modal z-index band ─────────────────
    useEffect(() => {
      if (!isOpen || !panelRef.current) return;
      overlay.open({
        id: panelId,
        type: 'modal',
        element: panelRef.current,
        priority: 10,
        config: { autoCloseOnOutsideClick: false },
        onClose: () => handleClose('programmatic'),
      });
      return () => {
        overlay.close(panelId);
      };
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Focus trap ──────────────────────────────────────────────────────
    useFocusTrap(panelRef, {
      active: isOpen,
      // When a confirm input exists, suppress trap's auto-focus and focus
      // the input ourselves below for guaranteed targeting.
      initialFocus: confirmInput ? 'none' : 'first',
      escapeDeactivates: false,
      returnFocusOnDeactivate: true,
      allowOutsideClick: false,
    });

    // Move focus to the confirm input once the panel is mounted/open
    useEffect(() => {
      if (!isOpen || !confirmInput) return;
      const id = window.setTimeout(() => {
        const input = panelRef.current?.querySelector<HTMLInputElement>(
          '.arvo-alert-dlg__confirm-input input',
        );
        if (input) {
          inputElRef.current = input;
          input.focus({ preventScroll: true });
        }
      }, 0);
      return () => window.clearTimeout(id);
    }, [isOpen, confirmInput]);

    // ── Escape key ──────────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen) return;
      const onKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') {
          e.stopPropagation();
          if (closeOnEscape) handleClose('escape');
        }
      };
      document.addEventListener('keydown', onKeyDown, true);
      return () => document.removeEventListener('keydown', onKeyDown, true);
    }, [isOpen, closeOnEscape, handleClose]);

    // ── Action click flow ───────────────────────────────────────────────
    const runAction = useCallback(
      (
        action: ArvoAlertDialogAction,
        reason: ArvoAlertDialogCloseReason,
        e: React.MouseEvent,
      ) => {
        const result = action.onClick?.(e);
        if (result === false) return;
        if (action.closeOnClick !== false) {
          handleClose(reason);
        }
      },
      [handleClose],
    );

    // Resolve action configs
    const primaryConfig = primaryAction ?? DEFAULT_PRIMARY;
    const secondaryConfig =
      secondaryAction === null ? null : secondaryAction ?? DEFAULT_SECONDARY;
    const showSecondary = hasSecondaryBtn && secondaryConfig !== null;

    const handlePrimaryClick = useCallback(
      (e: React.MouseEvent) => {
        if (isLoading || isDisabled || primaryConfig.isDisabled || isPrimaryDisabledByConfirm) return;
        runAction(primaryConfig, 'primary', e);
      },
      [isLoading, isDisabled, isPrimaryDisabledByConfirm, primaryConfig, runAction],
    );

    const handleSecondaryClick = useCallback(
      (e: React.MouseEvent) => {
        if (!secondaryConfig) return;
        runAction(secondaryConfig, 'secondary', e);
      },
      [secondaryConfig, runAction],
    );

    // ── Confirm input change & enter key ────────────────────────────────
    const handleConfirmInputChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const next = e.target.value;
        setConfirmValue(next);
        confirmInput?.onChange?.(next);
        onConfirmInputChange?.(next);
      },
      [confirmInput, onConfirmInputChange],
    );

    const handleConfirmInputKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' && !isPrimaryDisabledByConfirm) {
          e.preventDefault();
          runAction(
            primaryConfig,
            'primary',
            e as unknown as React.MouseEvent,
          );
        }
      },
      [isPrimaryDisabledByConfirm, primaryConfig, runAction],
    );

    // ── Don't-show-again change ─────────────────────────────────────────
    const handleDontShowChange = useCallback(
      (detail: { isChecked: boolean }) => {
        const next = detail.isChecked;
        setDontShowChecked(next);
        dontShowConfig?.onChange?.(next);
        onDontShowAgainChange?.(next);
      },
      [dontShowConfig, onDontShowAgainChange],
    );

    // ── Portal target ───────────────────────────────────────────────────
    const portalTarget = useMemo<HTMLElement | null>(() => {
      if (typeof document === 'undefined') return null;
      if (!container) return document.body;
      if (typeof container === 'string') {
        return (
          document.querySelector<HTMLElement>(container) ?? document.body
        );
      }
      return container;
    }, [container]);

    if (!isOpen || !portalTarget) return null;

    // ── Classes ─────────────────────────────────────────────────────────
    const rootClasses = [
      'arvo-alert-dlg',
      `arvo-alert-dlg--${variant}`,
      size !== 'md' && `arvo-alert-dlg--${size}`,
      hasBackdrop && 'arvo-alert-dlg--with-backdrop',
      hasDangerAction && 'arvo-alert-dlg--danger',
      isClosable && 'arvo-alert-dlg--closable',
      'open',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const dontShowLabel = dontShowConfig?.label ?? "Don't show this again";

    // ── Render ──────────────────────────────────────────────────────────
    return createPortal(
      <div ref={rootRef} className={rootClasses}>
        <div
          className="arvo-alert-dlg__backdrop"
          aria-hidden="true"
          onClick={
            closeOnBackdrop ? () => handleClose('backdrop') : undefined
          }
        />
        <div
          ref={panelRef}
          id={panelId}
          className="arvo-alert-dlg__panel"
          role="alertdialog"
          aria-modal="true"
          aria-labelledby={titleId}
          aria-describedby={bodyId}
          aria-busy={isLoading || undefined}
          tabIndex={-1}
        >
          <div className="arvo-alert-dlg__header">
            <span className="arvo-alert-dlg__ico o9con" aria-hidden="true" />
            <p id={titleId} className="arvo-alert-dlg__title">
              {title}
            </p>
            {isClosable && (
              <span className="arvo-alert-dlg__close-btn">
                <ArvoIconButton
                  icon="close"
                  variant="tertiary"
                  size="sm"
                  tooltip="Close"
                  aria-label="Close dialog"
                  isDisabled={isLoading || isDisabled}
                  onClick={() => handleClose('close-button')}
                />
              </span>
            )}
          </div>

          <div id={bodyId} className="arvo-alert-dlg__body">
            {content !== undefined && content !== null
              ? content
              : message && (
                  <p className="arvo-alert-dlg__msg">{message}</p>
                )}
            {confirmInput && (
              <div className="arvo-alert-dlg__confirm-input">
                <ArvoTextbox
                  size="sm"
                  isFullWidth
                  label={confirmInput.label}
                  placeholder={confirmInput.placeholder}
                  maxLength={confirmInput.maxLength}
                  value={confirmValue}
                  isDisabled={isLoading || isDisabled}
                  onChange={handleConfirmInputChange}
                  onKeyDown={handleConfirmInputKeyDown}
                />
              </div>
            )}
          </div>

          <div className="arvo-alert-dlg__footer">
            {dontShowConfig && (
              <div className="arvo-alert-dlg__dont-show">
                <ArvoCheckbox
                  size="sm"
                  label={dontShowLabel}
                  isChecked={dontShowChecked}
                  isDisabled={isLoading || isDisabled}
                  onChange={handleDontShowChange}
                />
              </div>
            )}
            <div className="arvo-alert-dlg__actions">
              {showSecondary && secondaryConfig && (
                <ArvoButton
                  label={secondaryConfig.label}
                  icon={secondaryConfig.icon}
                  variant="secondary"
                  size="md"
                  isDisabled={
                    isLoading || isDisabled || secondaryConfig.isDisabled
                  }
                  isLoading={secondaryConfig.isLoading}
                  onClick={handleSecondaryClick}
                />
              )}
              <ArvoButton
                label={primaryConfig.label}
                icon={primaryConfig.icon}
                variant={hasDangerAction ? 'danger' : 'primary'}
                size="md"
                isDisabled={
                  isLoading ||
                  isDisabled ||
                  primaryConfig.isDisabled ||
                  isPrimaryDisabledByConfirm
                }
                isLoading={primaryConfig.isLoading}
                onClick={handlePrimaryClick}
              />
            </div>
          </div>
        </div>
      </div>,
      portalTarget,
    );
  },
);

export { ArvoAlertDialog };
export default ArvoAlertDialog;
